      const fullPath = join(PROJECT_DIR, file);
      expect(existsSync(fullPath)).toBe(true);
    }
  });

  test("actionlint passes with exit code 0", () => {
    const yamlPath = join(PROJECT_DIR, ".github/workflows/test-results-aggregator.yml");
    let exitCode = 0;
