    const fixtures: Record<string, string> = {
      "matrix-run1.xml": readFileSync(join(PROJECT_DIR, "fixtures/matrix-run1.xml"), "utf-8"),
      "matrix-run2.xml": readFileSync(join(PROJECT_DIR, "fixtures/matrix-run2.xml"), "utf-8"),
